#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;std::vector<int> G[N],OP[N];int col[N],t[N],n,cnt,dfn[N],siz[N],lst[N],pp,num[N];
LL s[N],sum[N];
inline void ins(const int &x,const int &y){G[x].push_back(y);G[y].push_back(x);}
inline void dfs1(const int &u=1,const int &fa=0)
{
	siz[u]=1;dfn[u]=++cnt;for(int v: G[u])if(v!=fa)
	{
		int sv=num[col[u]];dfs1(v,u);siz[u]+=siz[v];int tmp=siz[v]+sv-num[col[u]];num[col[u]]+=tmp;s[v]+=tmp;
		while(OP[col[u]].size()&&dfn[OP[col[u]][OP[col[u]].size()-1]]>dfn[u]) s[OP[col[u]][OP[col[u]].size()-1]]-=tmp,OP[col[u]].pop_back();
	}
	++num[col[u]];OP[col[u]].push_back(u);
}
inline void dfs2(const int &u=1,const LL &w=s[1],const int &fa=0){sum[u]=w;for(int v: G[u])if(v!=fa)dfs2(v,w+s[v],u);}
int main()
{
	n=read();rep(1,n,i){int &x=t[read()];if(!x)x=++pp;col[i]=x;}
	rep(2,n,i)ins(read(),read());rep(1,pp,i)lst[i]=1;dfs1();
	rep(1,pp,i){s[1]+=n-num[i];for(int v: OP[i])s[v]-=n-num[i];} dfs2();
	rep(1,n,i)printf("%lld\n",1ll*pp*n-sum[i]);return 0;
}
